// Input Validation and Privacy Normalization
// Validates input schema, masks PII, validates photo reference, and attaches metadata

const item = $input.item.json;

// Initialize output object
const output = {
  validation_status: 'valid',
  validation_errors: [],
  original_input: item,
  normalized_input: {},
  metadata: {}
};

// Attach metadata
output.metadata.cx_id = item.cx_id || item.customer_id || 'anonymous_' + Date.now();
output.metadata.timestamp = new Date().toISOString();
output.metadata.caller_workflow = item.caller_workflow || $workflow.name || 'unknown';
output.metadata.workflow_execution_id = $execution.id;

// Validate required fields
const requiredFields = ['request_type'];
for (const field of requiredFields) {
  if (!item[field]) {
    output.validation_errors.push(`Missing required field: ${field}`);
    output.validation_status = 'invalid';
  }
}

// Validate request_type
const validRequestTypes = ['shade_match', 'beauty_advisory', 'support', 'qa'];
if (item.request_type && !validRequestTypes.includes(item.request_type)) {
  output.validation_errors.push(`Invalid request_type: ${item.request_type}. Must be one of: ${validRequestTypes.join(', ')}`);
  output.validation_status = 'invalid';
}

// PII Masking Function
function maskPII(text) {
  if (!text || typeof text !== 'string') return text;

  // Mask email addresses
  text = text.replace(/([a-zA-Z0-9._-]+)@([a-zA-Z0-9._-]+\.[a-zA-Z0-9_-]+)/gi, (match, user, domain) => {
    const maskedUser = user.substring(0, 2) + '***';
    return maskedUser + '@' + domain;
  });

  // Mask phone numbers (various formats)
  text = text.replace(/\b\d{3}[-.]?\d{3}[-.]?\d{4}\b/g, '***-***-****');

  // Mask credit card numbers
  text = text.replace(/\b\d{4}[\s-]?\d{4}[\s-]?\d{4}[\s-]?\d{4}\b/g, '****-****-****-****');

  // Mask SSN
  text = text.replace(/\b\d{3}-\d{2}-\d{4}\b/g, '***-**-****');

  return text;
}

// Normalize and mask input fields
output.normalized_input.request_type = item.request_type;
output.normalized_input.customer_query = maskPII(item.customer_query || item.query || '');
output.normalized_input.skin_tone = item.skin_tone || '';
output.normalized_input.undertone = item.undertone || '';
output.normalized_input.skin_type = item.skin_type || '';
output.normalized_input.concerns = item.concerns || [];
output.normalized_input.preferences = item.preferences || {};

// Validate photo reference if provided
if (item.photo_reference || item.photo_url) {
  const photoRef = item.photo_reference || item.photo_url;

  // Check if it's a valid URL or base64 string
  const isValidUrl = /^https?:\/\/.+/.test(photoRef);
  const isBase64 = /^data:image\/(png|jpg|jpeg|gif);base64,/.test(photoRef);

  if (isValidUrl || isBase64) {
    output.normalized_input.photo_reference = photoRef;
    output.normalized_input.has_photo = true;
  } else {
    output.validation_errors.push('Invalid photo_reference format. Must be a valid URL or base64 encoded image.');
    output.validation_status = 'invalid';
    output.normalized_input.has_photo = false;
  }
} else {
  output.normalized_input.has_photo = false;
}

// Mask any PII in customer name if provided
if (item.customer_name || item.name) {
  const name = item.customer_name || item.name;
  // Keep first name, mask last name
  const nameParts = name.split(' ');
  if (nameParts.length > 1) {
    output.normalized_input.customer_name = nameParts[0] + ' ' + nameParts[nameParts.length - 1].charAt(0) + '***';
  } else {
    output.normalized_input.customer_name = nameParts[0];
  }
}

// Add simulation mode flag
output.normalized_input.simulation_mode = item.simulation_mode || false;

// Return validation result
return output;

