// Universal Workflow Contract Validation (WF-0)
// Provides default values for missing fields, then validates the contract

const item = $input.item.json;

// Initialize validation result
const validationResult = {
  validation_passed: true,
  missing_fields: [],
  validated_input: {}
};

// Provide default values for missing required fields
const request_id = item.request_id || 'test_' + $execution.id;
const mode = item.mode || 'simulation';
const confidence = item.confidence !== null && item.confidence !== undefined ? item.confidence : 0.95;
const risk_level = item.risk_level || 'low';
const payload = item.payload || {};
const audit = item.audit || {
  timestamp: new Date().toISOString(),
  source_workflow: 'WF-7',
  execution_id: $execution.id
};

// Ensure audit has all required fields with defaults
if (!audit.timestamp) audit.timestamp = new Date().toISOString();
if (!audit.source_workflow) audit.source_workflow = 'WF-7';
if (!audit.execution_id) audit.execution_id = $execution.id;

// Define required fields from Universal Workflow Contract (WF-0)
const requiredFields = {
  request_id: request_id,
  mode: mode,
  confidence: confidence,
  risk_level: risk_level,
  payload: payload
};

// Validate that all required fields are now present (after defaults applied)
for (const [field, value] of Object.entries(requiredFields)) {
  // Check if field is still missing, null, or undefined (but allow 0 and false as valid values)
  if (value === null || value === undefined || value === '') {
    validationResult.validation_passed = false;
    validationResult.missing_fields.push(field);
  }
}

// Validate audit metadata (nested object)
if (!audit || typeof audit !== 'object' || audit === null) {
  validationResult.validation_passed = false;
  validationResult.missing_fields.push('audit');
} else {
  // Validate audit metadata fields
  const auditRequiredFields = ['timestamp', 'source_workflow', 'execution_id'];
  for (const auditField of auditRequiredFields) {
    const auditValue = audit[auditField];
    if (auditValue === null || auditValue === undefined || auditValue === '') {
      validationResult.validation_passed = false;
      validationResult.missing_fields.push(`audit.${auditField}`);
    }
  }
}

// Populate validated_input with all required fields (with defaults applied)
validationResult.validated_input = {
  request_id: request_id,
  mode: mode,
  confidence: confidence,
  risk_level: risk_level,
  payload: payload,
  audit: {
    timestamp: audit.timestamp,
    source_workflow: audit.source_workflow,
    execution_id: audit.execution_id
  },
  // Include optional fields if present
  founder_available: item.founder_available !== undefined ? item.founder_available : false,
  metadata: item.metadata || {},
  context: item.context || {}
};

// Return validation result
return validationResult;

// Sensitive Response Detection
// Classifies customer requests as normal, sensitive, or escalation
// Detects keywords for legal threats, safety issues, refunds, bias, and public complaints

const item = $input.item.json;

// Initialize output
const output = {
  response_sensitivity: false,
  sensitivity_category: 'normal',
  detected_triggers: [],
  original_data: item
};

// Get text to analyze from various possible fields
const textToAnalyze = [
  item.customer_query || '',
  item.normalized_input?.customer_query || '',
  item.query || '',
  JSON.stringify(item.preferences || {}),
  JSON.stringify(item.concerns || [])
].join(' ').toLowerCase();

// Define trigger keywords by category
const triggers = {
  legal_threat: [
    'lawyer', 'attorney', 'sue', 'lawsuit', 'legal action', 'court',
    'litigation', 'cease and desist', 'legal counsel', 'legal team',
    'take legal action', 'my lawyer', 'contact my attorney'
  ],
  safety_issue: [
    'allergic reaction', 'rash', 'burning', 'swelling', 'irritation',
    'chemical burn', 'injury', 'hurt', 'pain', 'medical attention',
    'hospital', 'doctor', 'emergency', 'severe reaction', 'poisoning',
    'toxic', 'dangerous', 'harmful', 'unsafe'
  ],
  refund_compensation: [
    'refund', 'money back', 'compensation', 'reimburse', 'chargeback',
    'dispute charge', 'want my money', 'demand refund', 'full refund',
    'partial refund', 'credit', 'store credit'
  ],
  bias_discrimination: [
    'racist', 'discrimination', 'discriminate', 'bias', 'biased',
    'prejudice', 'unfair', 'offensive', 'insensitive', 'colorism',
    'skin tone bias', 'shade range', 'lack of diversity', 'not inclusive',
    'excluded', 'marginalized'
  ],
  public_complaint: [
    'social media', 'twitter', 'instagram', 'facebook', 'tiktok',
    'influencer', 'post about this', 'tell everyone', 'review',
    'bad review', 'public complaint', 'expose', 'viral', 'followers',
    'going public', 'share this experience', 'warn others'
  ]
};

// Check for triggers in each category
for (const [category, keywords] of Object.entries(triggers)) {
  for (const keyword of keywords) {
    if (textToAnalyze.includes(keyword)) {
      output.detected_triggers.push({
        category: category,
        keyword: keyword,
        severity: category === 'legal_threat' || category === 'safety_issue' ? 'high' : 'medium'
      });
      output.response_sensitivity = true;
    }
  }
}

// Determine sensitivity category based on detected triggers
if (output.detected_triggers.length === 0) {
  output.sensitivity_category = 'normal';
} else {
  // Check for escalation-level triggers
  const hasLegalThreat = output.detected_triggers.some(t => t.category === 'legal_threat');
  const hasSafetyIssue = output.detected_triggers.some(t => t.category === 'safety_issue');
  const hasPublicComplaint = output.detected_triggers.some(t => t.category === 'public_complaint');

  if (hasLegalThreat || hasSafetyIssue) {
    output.sensitivity_category = 'escalation';
  } else if (hasPublicComplaint || output.detected_triggers.length >= 3) {
    output.sensitivity_category = 'escalation';
  } else {
    output.sensitivity_category = 'sensitive';
  }
}

// Add metadata
output.analysis_timestamp = new Date().toISOString();
output.trigger_count = output.detected_triggers.length;

// Return merged output with original data
return { ...item, ...output };

// Enhanced Audit Record Generation
// Generates immutable audit record for WF-0 consumption

const items = $input.all();
const auditRecords = [];

for (const item of items) {
  const json = item.json;

  // Generate unique request ID if not present
  const requestId = json.request_id || json.metadata?.workflow_execution_id || $execution.id + '_' + Date.now();

  // Determine mode (simulation vs production)
  const mode = json.normalized_input?.simulation_mode === true ? 'simulation' : 'production';

  // Extract confidence score
  const confidenceScore = json.confidence_score || 0;

  // Determine sensitivity classification
  let sensitivityClassification = 'standard';
  if (json.sensitivity_flags) {
    if (json.sensitivity_flags.high_risk || json.risk_level === 'high') {
      sensitivityClassification = 'high';
    } else if (json.sensitivity_flags.medium_risk || json.risk_level === 'medium') {
      sensitivityClassification = 'medium';
    }
  }

  // Extract CREA decision
  const creaDecision = json.CREA_approved !== undefined ? 
    (json.CREA_approved ? 'approved' : 'rejected') : 
    'not_required';

  // Determine founder availability (if founder gate was triggered)
  const founderAvailability = json.founder_approval_required === true ? 
    (json.founder_approved === true ? 'approved' : 'pending') : 
    'not_required';

  // Determine response status
  let responseSentOrBlockedReason = 'sent';
  if (json.status === 'blocked' || json.blocked === true) {
    if (json.blocking_reason) {
      responseSentOrBlockedReason = json.blocking_reason;
    } else if (confidenceScore < 0.75) {
      responseSentOrBlockedReason = 'blocked_low_confidence';
    } else if (creaDecision === 'rejected') {
      responseSentOrBlockedReason = 'blocked_crea_rejected';
    } else if (mode === 'simulation') {
      responseSentOrBlockedReason = 'blocked_simulation_mode';
    } else {
      responseSentOrBlockedReason = 'blocked_unknown';
    }
  } else if (json.status === 'paused' || founderAvailability === 'pending') {
    responseSentOrBlockedReason = 'paused_founder_approval_required';
  }

  // Track all gates passed
  const allGatesPassed = [];
  if (json.validation_status === 'valid') allGatesPassed.push('contract_validation');
  if (confidenceScore >= 0.75) allGatesPassed.push('confidence_gate');
  if (json.shade_available !== false) allGatesPassed.push('shade_availability');
  if (creaDecision === 'approved' || creaDecision === 'not_required') allGatesPassed.push('crea_gate');
  if (founderAvailability === 'approved' || founderAvailability === 'not_required') allGatesPassed.push('founder_gate');
  if (json.qa_check?.approved === true) allGatesPassed.push('qa_gate');
  if (mode === 'production') allGatesPassed.push('execution_safety_gate');

  // Determine blocking gate (if any)
  let blockingGate = null;
  if (responseSentOrBlockedReason.startsWith('blocked_')) {
    if (responseSentOrBlockedReason === 'blocked_low_confidence') {
      blockingGate = 'confidence_gate';
    } else if (responseSentOrBlockedReason === 'blocked_crea_rejected') {
      blockingGate = 'crea_gate';
    } else if (responseSentOrBlockedReason === 'blocked_simulation_mode') {
      blockingGate = 'execution_safety_gate';
    } else if (json.validation_status === 'invalid') {
      blockingGate = 'contract_validation';
    }
  } else if (responseSentOrBlockedReason === 'paused_founder_approval_required') {
    blockingGate = 'founder_gate';
  }

  // Build immutable audit record
  const auditRecord = {
    request_id: requestId,
    mode: mode,
    confidence: confidenceScore,
    sensitivity_classification: sensitivityClassification,
    crea_decision: creaDecision,
    founder_availability: founderAvailability,
    response_sent_or_blocked_reason: responseSentOrBlockedReason,
    timestamp: new Date().toISOString(),
    workflow_id: $workflow.id,
    workflow_name: $workflow.name,
    execution_id: $execution.id,
    all_gates_passed: allGatesPassed,
    blocking_gate: blockingGate,

    // Additional context for WF-0
    customer_id: json.metadata?.cx_id || json.cx_id || 'unknown',
    request_type: json.normalized_input?.request_type || json.request_type || 'unknown',
    sentiment: json.sentiment || 'neutral',
    escalation_needed: json.support_response?.escalation_needed || false,
    shade_recommendation: json.shade_recommendation || null,

    // Full payload for deep analysis (optional)
    full_context: {
      validation_errors: json.validation_errors || [],
      sensitivity_flags: json.sensitivity_flags || {},
      qa_check: json.qa_check || {},
      support_response: json.support_response || {}
    }
  };

  auditRecords.push({ json: auditRecord });
}

return auditRecords;

